'use client';

import { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { useAuth } from './AuthContext';

export interface Project {
  id: string;
  name: string;
  description: string;
  type: 'developer' | 'marketing';
  status: 'active' | 'planning' | 'on-hold' | 'completed';
  progress: number;
  startDate?: string;
  endDate?: string;
  createdAt: Date;
  updatedAt: Date;
  // Developer project fields
  repositoryLink?: string;
  techStack?: string;
  versionControl?: 'github' | 'gitlab' | 'bitbucket' | 'other';
  // Marketing project fields
  campaignGoal?: string;
  budget?: string;
  channels?: string;
  targetAudience?: string;
  // Metadata
  tasks: number;
  members: number;
  isStarred: boolean;
  language: string;
}

interface ProjectsContextType {
  projects: Project[];
  addProject: (project: Omit<Project, 'id' | 'createdAt' | 'updatedAt' | 'tasks' | 'members' | 'isStarred' | 'language'>) => void;
  updateProject: (id: string, updates: Partial<Project>) => void;
  deleteProject: (id: string) => void;
  toggleStar: (id: string) => void;
  getProjectsByType: (type: Project['type']) => Project[];
  getProjectsByStatus: (status: Project['status']) => Project[];
  getStarredProjects: () => Project[];
}

const ProjectsContext = createContext<ProjectsContextType | undefined>(undefined);

export function ProjectsProvider({ children }: { children: ReactNode }) {
  const { user } = useAuth();
  const [projects, setProjects] = useState<Project[]>([]);

  const storageKey = user ? `projects_${user.id}` : null;

  // One-time migration: remove the old unscoped 'projects' key
  useEffect(() => {
    localStorage.removeItem('projects');
  }, []);

  // Load projects from localStorage when the user changes
  useEffect(() => {
    if (!storageKey) {
      setProjects([]);
      return;
    }
    const savedProjects = localStorage.getItem(storageKey);
    if (savedProjects) {
      try {
        const parsed = JSON.parse(savedProjects);
        const projectsWithDates = parsed.map((p: any) => ({
          ...p,
          createdAt: new Date(p.createdAt),
          updatedAt: new Date(p.updatedAt),
        }));
        setProjects(projectsWithDates);
      } catch (error) {
        console.error('Error loading projects:', error);
        setProjects([]);
      }
    } else {
      setProjects([]);
    }
  }, [storageKey]);

  // Save projects to localStorage whenever they change (only when logged in)
  useEffect(() => {
    if (!storageKey) return;
    localStorage.setItem(storageKey, JSON.stringify(projects));
  }, [projects, storageKey]);

  const addProject = (projectData: Omit<Project, 'id' | 'createdAt' | 'updatedAt' | 'tasks' | 'members' | 'isStarred' | 'language'>) => {
    const newProject: Project = {
      ...projectData,
      id: Date.now().toString() + Math.random().toString(36).substr(2, 9),
      createdAt: new Date(),
      updatedAt: new Date(),
      tasks: 0,
      members: 1,
      isStarred: false,
      language: projectData.type === 'developer' ? (projectData.techStack || 'Code') : 'Campaign',
    };

    setProjects(prev => [newProject, ...prev]);
  };

  const updateProject = (id: string, updates: Partial<Project>) => {
    setProjects(prev =>
      prev.map(project =>
        project.id === id 
          ? { ...project, ...updates, updatedAt: new Date() }
          : project
      )
    );
  };

  const deleteProject = (id: string) => {
    setProjects(prev => prev.filter(project => project.id !== id));
  };

  const toggleStar = (id: string) => {
    setProjects(prev =>
      prev.map(project =>
        project.id === id 
          ? { ...project, isStarred: !project.isStarred, updatedAt: new Date() }
          : project
      )
    );
  };

  const getProjectsByType = (type: Project['type']) => {
    return projects.filter(project => project.type === type);
  };

  const getProjectsByStatus = (status: Project['status']) => {
    return projects.filter(project => project.status === status);
  };

  const getStarredProjects = () => {
    return projects.filter(project => project.isStarred);
  };

  return (
    <ProjectsContext.Provider
      value={{
        projects,
        addProject,
        updateProject,
        deleteProject,
        toggleStar,
        getProjectsByType,
        getProjectsByStatus,
        getStarredProjects,
      }}
    >
      {children}
    </ProjectsContext.Provider>
  );
}

export function useProjects() {
  const context = useContext(ProjectsContext);
  if (context === undefined) {
    throw new Error('useProjects must be used within a ProjectsProvider');
  }
  return context;
}
